    const [elements, setElements] = useState<DrawElement[]>([]);
    const [selectedElementId, setSelectedElementId] = useState<string | null>(null);
    const [isGenerating, setIsGenerating] = useState(false);
    const [error, setError] = useState('');
    const [projectName, setProjectName] = useState('مشروع رسم جديد');
    const canvasRef = useRef<HTMLDivElement>(null);

    const [isUpgradeModalOpen, setUpgradeModalOpen] = useState(false);
    const { incrementUsage, isLimitReached } = useUsage();
    const { currentUser } = useAuth();

    // --- Gallery Logic ---
    useEffect(() => {
        if (screen === 'gallery' && currentUser?.email) {
            const allProjects: Project[] = JSON.parse(localStorage.getItem(`appProjects_${currentUser.email}`) || '[]');
            const drawProjects = allProjects.filter(p => p.creationMode === 'drawToCode');
            setProjects(drawProjects);
        }
    }, [screen, currentUser]);

    const handleCreateNew = () => {
        setElements([]);
        setProjectName(`مشروع رسم ${new Date().toLocaleDateString('ar-EG')}`);
        setScreen('editor');
    };

    const handleDeleteProject = (id: string) => {
        if (!currentUser?.email) return;
        const updatedProjects = projects.filter(p => p.id !== id);
        setProjects(updatedProjects);

        const allProjects: Project[] = JSON.parse(localStorage.getItem(`appProjects_${currentUser.email}`) || '[]');
        const newAllProjects = allProjects.filter(p => p.id !== id);
        localStorage.setItem(`appProjects_${currentUser.email}`, JSON.stringify(newAllProjects));
    };

    // --- Editor Logic ---
    const addElement = (type: DrawElement['type'], content?: string) => {
        const newElement: DrawElement = {
            id: `el-${Date.now()}`,
            type,
            content,
            x: 100,
            y: 100,
            width: type === 'rect' || type === 'circle' ? 100 : undefined,
            height: type === 'rect' || type === 'circle' ? 100 : undefined,
            color: '#6366f1', // Default Indigo
        };
        setElements(prev => [...prev, newElement]);
        setSelectedElementId(newElement.id);
    };

    const updateElement = (id: string, updates: Partial<DrawElement>) => {
        setElements(prev => prev.map(el => el.id === id ? { ...el, ...updates } : el));
    };

    const removeElement = (id: string) => {
        setElements(prev => prev.filter(el => el.id !== id));
        setSelectedElementId(null);
    };

    // Simple Drag Logic (very basic for demonstration)
    const handleMouseDown = (e: React.MouseEvent, id: string) => {
        setSelectedElementId(id);
        const startX = e.clientX;
        const startY = e.clientY;
        const el = elements.find(e => e.id === id);
        if (!el) return;
        const initX = el.x;
        const initY = el.y;

        const handleMouseMove = (moveEvent: MouseEvent) => {
            const dx = moveEvent.clientX - startX;
            const dy = moveEvent.clientY - startY;
            updateElement(id, { x: initX + dx, y: initY + dy });
        };

        const handleMouseUp = () => {
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
        };

        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
    };

    const handleConvert = async () => {
        if (elements.length === 0) {
            setError('اللوحة فارغة! أضف بعض العناصر أولاً.');
            return;
        }
        if (isLimitReached(ProjectType.DRAW_TO_CODE)) {
            setUpgradeModalOpen(true);
            return;
        }

        setIsGenerating(true);
        setError('');

        try {
            // Describe the layout to Gemini
            const description = elements.map(el => {
                if (el.type === 'emoji' || el.type === 'text') return `Text/Emoji '${el.content}' at position (${el.x}, ${el.y})`;
                return `${el.type} shape colored ${el.color} at (${el.x}, ${el.y}) size ${el.width}x${el.height}`;
            }).join('. ');

            const prompt = `Create a web page based on this visual layout description. The user drew these elements on a canvas. Translate emojis into functional components (e.g., a bell emoji becomes a notification button/icon, a cart emoji becomes a shopping cart). 

            Layout Description: ${description}.

            Project Name: ${projectName}.

            The output must be a complete project with HTML, CSS (using Tailwind), and JS.`;

            const newProject = await geminiService.buildProjectFromSpec({
                projectName,
                prompt,
                projectType: ProjectType.WEBSITE,
                files: [], // No images, just text description
            }, (log) => console.log(log));

            newProject.creationMode = 'drawToCode';
            newProject.id = `draw-${Date.now()}`;

            if (currentUser?.email) {
                const key = `appProjects_${currentUser.email}`;
                const savedApps: Project[] = JSON.parse(localStorage.getItem(key) || '[]');
                savedApps.unshift(newProject);
                localStorage.setItem(key, JSON.stringify(savedApps));
            }

            incrementUsage(ProjectType.DRAW_TO_CODE);
            navigate('editApp', { project: newProject });

        } catch (e) {
            setError('فشل التحويل. حاول مرة أخرى.');
            console.error(e);
        } finally {
            setIsGenerating(false);
        }
    };

    if (screen === 'gallery') {
        return (
            <div className="p-6 h-full flex flex-col animate-fade-in space-y-6">
                <header className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold text-white flex items-center gap-2">
                            <PaintBrushIcon className="w-8 h-8 text-pink-500"/> رسمة إلى كود
                        </h1>
                        <p className="text-slate-400">ارسم واجهتك وحولها إلى تطبيق حقيقي.</p>
                    </div>
                    <button onClick={handleCreateNew} className="bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-2 px-4 rounded-lg flex items-center gap-2">
                        <PlusIcon className="w-5 h-5"/> رسم جديد
                    </button>
                </header>

                {projects.length === 0 ? (
                    <div className="flex-grow flex flex-col items-center justify-center text-slate-500 border-2 border-dashed border-slate-700 rounded-xl">
                        <PaintBrushIcon className="w-16 h-16 mb-4 opacity-50"/>
                        <p>لا توجد رسومات محفوظة.</p>
                        <button onClick={handleCreateNew} className="text-indigo-400 hover:underline mt-2">ابدأ الرسم الآن</button>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 overflow-y-auto">
                        {projects.map(p => (
                            <ProjectCard 
                                key={p.id}
                                project={p}
                                onDelete={handleDeleteProject}
                                onEdit={(proj) => navigate('editApp', { project: proj })}
                            />
                        ))}
                    </div>
                )}
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full bg-slate-900 text-white animate-fade-in">
            {/* Toolbar Header */}
            <header className="flex-shrink-0 p-4 border-b border-slate-700 flex justify-between items-center bg-slate-800">
                <div className="flex items-center gap-4">
                    <button onClick={() => setScreen('gallery')} className="p-2 rounded-full hover:bg-slate-700 text-slate-400 hover:text-white">
                        <ArrowLeftIcon className="w-5 h-5"/>
                    </button>
                    <input 
                        type="text" 
                        value={projectName} 
                        onChange={e => setProjectName(e.target.value)}
                        className="bg-transparent border-b border-transparent hover:border-slate-500 focus:border-indigo-500 outline-none font-bold text-lg"
                    />
                </div>
                <div className="flex items-center gap-2">
                    {isGenerating && <span className="text-xs text-indigo-400 animate-pulse">جاري التحويل...</span>}
                    <button onClick={handleConvert} disabled={isGenerating} className="bg-green-600 hover:bg-green-500 text-white font-bold py-2 px-6 rounded-lg flex items-center gap-2 shadow-lg shadow-green-900/20 disabled:bg-slate-600">
                        {isGenerating ? <SpinnerIcon className="w-5 h-5 animate-spin"/> : <CodeIcon className="w-5 h-5"/>}
                        تحويل إلى كود
                    </button>
                </div>
            </header>

            {/* Main Canvas Area */}
            <div className="flex-grow relative overflow-hidden bg-[#1e1e1e]" ref={canvasRef}>
                {/* Grid Background */}
                <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(#4f46e5 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

                {elements.map(el => (
                    <div
                        key={el.id}
                        onMouseDown={(e) => handleMouseDown(e, el.id)}
                        style={{
                            position: 'absolute',
                            left: el.x,
                            top: el.y,
                            width: el.width,
                            height: el.height,
                            backgroundColor: el.type === 'rect' || el.type === 'circle' ? el.color : 'transparent',
                            borderRadius: el.type === 'circle' ? '50%' : '4px',
                            border: selectedElementId === el.id ? '2px dashed #6366f1' : 'none',
                            cursor: 'move',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            fontSize: '2rem',
                            userSelect: 'none'
                        }}
                    >
                        {el.content}
                    </div>
                ))}
            </div>

            {/* Bottom Toolbar */}
            <div className="flex-shrink-0 p-4 bg-slate-800 border-t border-slate-700 flex justify-center gap-4">
                <button onClick={() => addElement('emoji', '🔔')} className="p-3 rounded-xl bg-slate-700 hover:bg-indigo-600 transition-colors text-2xl" title="إشعار">🔔</button>
                <button onClick={() => addElement('emoji', '🛒')} className="p-3 rounded-xl bg-slate-700 hover:bg-indigo-600 transition-colors text-2xl" title="عربة تسوق">🛒</button>
                <button onClick={() => addElement('emoji', '👤')} className="p-3 rounded-xl bg-slate-700 hover:bg-indigo-600 transition-colors text-2xl" title="مستخدم">👤</button>
                <button onClick={() => addElement('emoji', '🏠')} className="p-3 rounded-xl bg-slate-700 hover:bg-indigo-600 transition-colors text-2xl" title="منزل">🏠</button>
                <div className="w-px bg-slate-600 mx-2"></div>
                <button onClick={() => addElement('rect')} className="p-3 rounded-xl bg-slate-700 hover:bg-indigo-600 transition-colors flex flex-col items-center gap-1">
                    <div className="w-6 h-4 border-2 border-white rounded-sm"></div>
                    <span className="text-[10px]">مستطيل</span>
                </button>
                <button onClick={() => addElement('circle')} className="p-3 rounded-xl bg-slate-700 hover:bg-indigo-600 transition-colors flex flex-col items-center gap-1">
                    <div className="w-5 h-5 border-2 border-white rounded-full"></div>
                    <span className="text-[10px]">دائرة</span>
                </button>
                <div className="w-px bg-slate-600 mx-2"></div>
                {selectedElementId && (
                    <button onClick={() => removeElement(selectedElementId)} className="p-3 rounded-xl bg-red-500/20 text-red-400 hover:bg-red-500 hover:text-white transition-colors">
                        <TrashIcon className="w-6 h-6"/>
                    </button>
                )}
            </div>

            {error && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 bg-red-500 text-white px-4 py-2 rounded-full shadow-lg">
                    {error}
                </div>
            )}
            <UpgradeModal isOpen={isUpgradeModalOpen} onClose={() => setUpgradeModalOpen(false)} />
        </div>
    );
};

export default DrawToCode;
