        }

        setIsGenerating(true);
        setError('');

        try {
            // Build a structured description of the scene
            const sceneDescription = elements.map(el => {
                let desc = `- Type: ${el.type}, Position: (${el.x},${el.y}), Size: ${el.width}x${el.height}`;
                if (el.backgroundColor) desc += `, Background: ${el.backgroundColor}`;
                if (el.content) desc += `, Content/Text: "${el.content}"`;
                if (el.textColor) desc += `, Text Color: ${el.textColor}`;
                if (el.borderRadius) desc += `, Radius: ${el.borderRadius}`;
                return desc;
            }).join('\n');

            const prompt = `
            I have drawn a UI design on a canvas. Convert this visual layout into a responsive HTML/TailwindCSS web page.

            **Design Elements:**
            ${sceneDescription}

            **Instructions:**
            1. Create a clean, modern layout based on the positioning provided.
            2. Use absolute positioning only if necessary, prefer Flexbox/Grid for responsiveness if items align.
            3. 'rect' usually means a container, card, or section background.
            4. 'input' means an HTML input field.
            5. 'button' is a clickable button.
            6. 'image' is a placeholder for an <img> tag.
            7. Match colors and styling as close as possible.

            **Project Name:** ${projectName}

            Output valid JSON with 'files' array (index.html, style.css, script.js).
            `;

            const newProject = await geminiService.buildProjectFromSpec({
                projectName,
                prompt,
                projectType: ProjectType.WEBSITE,
                files: [],
            }, (log) => console.log(log));

            newProject.creationMode = 'drawToCode';
            newProject.id = `draw-${Date.now()}`;

            if (currentUser?.email) {
                const key = `appProjects_${currentUser.email}`;
                const savedApps: Project[] = JSON.parse(localStorage.getItem(key) || '[]');
                savedApps.unshift(newProject);
                localStorage.setItem(key, JSON.stringify(savedApps));
            }

            incrementUsage(ProjectType.DRAW_TO_CODE);
            navigate('editApp', { project: newProject });

        } catch (e) {
            setError('فشل التحويل. حاول مرة أخرى.');
            console.error(e);
        } finally {
            setIsGenerating(false);
        }
    };

    // --- Rendering ---

    if (screen === 'gallery') {
        return (
            <div className="p-6 h-full flex flex-col animate-fade-in space-y-6">
                <header className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl font-bold text-white flex items-center gap-2">
                            <PaintBrushIcon className="w-8 h-8 text-pink-500"/> رسمة إلى كود
                        </h1>
                        <p className="text-slate-400">صمم واجهتك بأدوات رسم ذكية وحولها إلى كود حقيقي.</p>
                    </div>
                    <button onClick={handleCreateNew} className="bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-2 px-4 rounded-lg flex items-center gap-2">
                        <PlusIcon className="w-5 h-5"/> تصميم جديد
                    </button>
                </header>

                {projects.length === 0 ? (
                    <div className="flex-grow flex flex-col items-center justify-center text-slate-500 border-2 border-dashed border-slate-700 rounded-xl bg-slate-800/30">
                        <PaintBrushIcon className="w-16 h-16 mb-4 opacity-50"/>
                        <p>لا توجد تصميمات محفوظة.</p>
                        <button onClick={handleCreateNew} className="text-indigo-400 hover:underline mt-2">ابدأ التصميم الآن</button>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 overflow-y-auto">
                        {projects.map(p => (
                            <ProjectCard 
                                key={p.id}
                                project={p}
                                onDelete={(id) => {
                                    const updatedProjects = projects.filter(proj => proj.id !== id);
                                    setProjects(updatedProjects);
                                    if (currentUser?.email) {
                                        localStorage.setItem(`appProjects_${currentUser.email}`, JSON.stringify(updatedProjects));
                                    }
                                }}
                                onEdit={(proj) => navigate('editApp', { project: proj })}
                            />
                        ))}
                    </div>
                )}
            </div>
        );
    }

    const selectedElement = elements.find(el => selectedIds.includes(el.id));

    return (
        <div className="flex flex-col h-full bg-slate-900 text-white animate-fade-in overflow-hidden">
            {/* Top Header */}
            <header className="h-16 bg-slate-800 border-b border-slate-700 flex items-center justify-between px-4 flex-shrink-0 z-20">
                <div className="flex items-center gap-4">
                    <button onClick={() => setScreen('gallery')} className="p-2 rounded-full hover:bg-slate-700 text-slate-400 hover:text-white">
                        <ArrowLeftIcon className="w-5 h-5"/>
                    </button>
                    <input 
                        type="text" 
                        value={projectName} 
                        onChange={e => setProjectName(e.target.value)}
                        className="bg-transparent border-b border-transparent hover:border-slate-500 focus:border-indigo-500 outline-none font-bold text-lg px-2 py-1"
                    />
                </div>
                <div className="flex items-center gap-3">
                    {isGenerating && <span className="text-xs text-indigo-400 animate-pulse">جاري التحويل والذكاء...</span>}
                    <button onClick={handleConvert} disabled={isGenerating} className="bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white font-bold py-2 px-6 rounded-lg flex items-center gap-2 shadow-lg transition-all disabled:opacity-50">
                        {isGenerating ? <SpinnerIcon className="w-5 h-5 animate-spin"/> : <CodeIcon className="w-5 h-5"/>}
                        تحويل إلى كود
                    </button>
                </div>
            </header>

            <div className="flex-grow flex overflow-hidden">
                {/* Left Toolbar */}
                <aside className="w-16 bg-slate-800 border-r border-slate-700 flex flex-col items-center py-4 gap-4 z-10">
                    <ToolButton icon={<CursorArrowRaysIcon className="w-6 h-6"/>} label="تحديد" active={activeTool === 'select'} onClick={() => setActiveTool('select')} />
                    <div className="w-8 h-px bg-slate-700 my-2"></div>
                    <ToolButton icon={<StopIcon className="w-6 h-6"/>} label="صندوق" onClick={() => addElement('rect')} />
                    <ToolButton icon={<div className="w-5 h-5 rounded-full border-2 border-current"/>} label="دائرة" onClick={() => addElement('circle')} />
                    <ToolButton icon={<ChatBubbleBottomCenterTextIcon className="w-6 h-6"/>} label="نص" onClick={() => addElement('text')} />
                    <ToolButton icon={<div className="w-6 h-3 bg-current rounded-sm"/>} label="زر" onClick={() => addElement('button')} />
                    <ToolButton icon={<div className="w-6 h-4 border border-current rounded-sm text-[8px] flex items-center px-1">|</div>} label="إدخال" onClick={() => addElement('input')} />
                    <ToolButton icon={<PhotoIcon className="w-6 h-6"/>} label="صورة" onClick={() => addElement('image')} />
                    <ToolButton icon={<SparklesIcon className="w-6 h-6"/>} label="أيقونة" onClick={() => addElement('icon')} />
                </aside>

                {/* Center Canvas */}
                <main 
                    className="flex-grow bg-[#1e1e2e] relative overflow-hidden select-none"
                    ref={canvasRef}
                    onMouseMove={handleCanvasMouseMove}
                    onMouseUp={handleMouseUp}
                    onMouseLeave={handleMouseUp}
                    onClick={handleCanvasClick}
                >
                    {/* Grid Background */}
                    <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#6366f1 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

                    {elements.map(el => {
                        const isSelected = selectedIds.includes(el.id);
                        return (
                            <div
                                key={el.id}
                                onMouseDown={(e) => handleMouseDown(e, el.id, 'drag')}
                                style={{
                                    position: 'absolute',
                                    left: el.x,
                                    top: el.y,
                                    width: el.width,
                                    height: el.height,
                                    backgroundColor: el.backgroundColor,
                                    color: el.textColor,
                                    borderColor: el.borderColor,
                                    borderWidth: el.borderWidth ? `${el.borderWidth}px` : undefined,
                                    borderStyle: el.borderWidth ? 'solid' : undefined,
                                    borderRadius: el.borderRadius ? `${el.borderRadius}px` : undefined,
                                    fontSize: el.fontSize ? `${el.fontSize}px` : undefined,
                                    zIndex: el.zIndex,
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    cursor: activeTool === 'select' ? 'move' : 'default',
                                    boxShadow: isSelected ? '0 0 0 2px #6366f1, 0 10px 15px -3px rgba(0, 0, 0, 0.1)' : 'none',
                                    overflow: 'hidden',
                                    whiteSpace: 'nowrap'
                                }}
                                className="transition-shadow"
                            >
                                {el.type === 'image' ? (
                                    <div className="flex flex-col items-center justify-center text-slate-400/50 w-full h-full bg-slate-200/10">
                                        <PhotoIcon className="w-1/3 h-1/3"/>
                                        <span className="text-xs mt-1">صورة</span>
                                    </div>
                                ) : (
                                    el.content
                                )}

                                {/* Resize Handle */}
                                {isSelected && (
                                    <div 
                                        onMouseDown={(e) => handleMouseDown(e, el.id, 'resize')}
                                        className="absolute bottom-0 right-0 w-4 h-4 bg-indigo-600 cursor-nwse-resize z-50"
                                        style={{ borderRadius: '4px 0 4px 0' }}
                                    />
                                )}
                            </div>
                        );
                    })}
                </main>

                {/* Right Properties Panel */}
                <aside className="w-72 bg-slate-800 border-l border-slate-700 p-4 flex flex-col overflow-y-auto z-10">
                    <h3 className="font-bold text-slate-200 mb-4 border-b border-slate-700 pb-2">الخصائص</h3>

                    {selectedElement ? (
                        <div className="space-y-4">
                            <div className="space-y-2">
                                <label className="text-xs text-slate-400">المحتوى / النص</label>
                                <input 
                                    type="text" 
                                    value={selectedElement.content || ''} 
                                    onChange={(e) => updateSelectedElement({ content: e.target.value })}
                                    className="w-full bg-slate-700 border border-slate-600 rounded px-2 py-1 text-white text-sm"
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-2">
                                <div className="space-y-1">
                                    <label className="text-xs text-slate-400">العرض</label>
                                    <input type="number" value={selectedElement.width} onChange={(e) => updateSelectedElement({ width: parseInt(e.target.value) })} className="w-full bg-slate-700 border border-slate-600 rounded px-2 py-1 text-white text-sm" />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-xs text-slate-400">الارتفاع</label>
                                    <input type="number" value={selectedElement.height} onChange={(e) => updateSelectedElement({ height: parseInt(e.target.value) })} className="w-full bg-slate-700 border border-slate-600 rounded px-2 py-1 text-white text-sm" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs text-slate-400">لون الخلفية</label>
                                <div className="flex gap-2 items-center">
                                    <input type="color" value={selectedElement.backgroundColor || '#ffffff'} onChange={(e) => updateSelectedElement({ backgroundColor: e.target.value })} className="w-8 h-8 p-0 border-0 rounded cursor-pointer" />
                                    <input type="text" value={selectedElement.backgroundColor || ''} onChange={(e) => updateSelectedElement({ backgroundColor: e.target.value })} className="flex-grow bg-slate-700 border border-slate-600 rounded px-2 py-1 text-white text-sm font-mono" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs text-slate-400">لون النص</label>
                                <div className="flex gap-2 items-center">
                                    <input type="color" value={selectedElement.textColor || '#000000'} onChange={(e) => updateSelectedElement({ textColor: e.target.value })} className="w-8 h-8 p-0 border-0 rounded cursor-pointer" />
                                    <input type="text" value={selectedElement.textColor || ''} onChange={(e) => updateSelectedElement({ textColor: e.target.value })} className="flex-grow bg-slate-700 border border-slate-600 rounded px-2 py-1 text-white text-sm font-mono" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs text-slate-400">حجم الخط ({selectedElement.fontSize}px)</label>
                                <input 
                                    type="range" min="10" max="100" 
                                    value={selectedElement.fontSize || 16} 
                                    onChange={(e) => updateSelectedElement({ fontSize: parseInt(e.target.value) })}
                                    className="w-full"
                                />
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs text-slate-400">نصف القطر ({selectedElement.borderRadius}px)</label>
                                <input 
                                    type="range" min="0" max="50" 
                                    value={selectedElement.borderRadius || 0} 
                                    onChange={(e) => updateSelectedElement({ borderRadius: parseInt(e.target.value) })}
                                    className="w-full"
                                />
                            </div>

                            <div className="pt-4 border-t border-slate-700 flex flex-col gap-2">
                                <div className="flex gap-2">
                                    <button onClick={handleBringToFront} className="flex-1 bg-slate-700 hover:bg-slate-600 text-xs py-2 rounded text-slate-300">للأمام</button>
                                    <button onClick={handleSendToBack} className="flex-1 bg-slate-700 hover:bg-slate-600 text-xs py-2 rounded text-slate-300">للخلف</button>
                                </div>
                                <button onClick={handleDeleteSelected} className="bg-red-500/20 hover:bg-red-500/40 text-red-400 text-sm py-2 rounded flex items-center justify-center gap-2">
                                    <TrashIcon className="w-4 h-4" /> حذف العنصر
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="text-center text-slate-500 mt-10">
                            <HandRaisedIcon className="w-10 h-10 mx-auto mb-2 opacity-50"/>
                            <p className="text-sm">حدد عنصرًا لتعديل خصائصه</p>
                        </div>
                    )}
                </aside>
            </div>

            {error && (
                <div className="absolute bottom-20 left-1/2 -translate-x-1/2 bg-red-500 text-white px-4 py-2 rounded-full shadow-lg z-50">
                    {error}
                </div>
            )}
            <UpgradeModal isOpen={isUpgradeModalOpen} onClose={() => setUpgradeModalOpen(false)} />
        </div>
    );
};

const ToolButton: React.FC<{ icon: React.ReactNode; label: string; onClick: () => void; active?: boolean }> = ({ icon, label, onClick, active }) => (
    <button 
        onClick={onClick} 
        className={`p-2 rounded-lg flex flex-col items-center gap-1 w-12 h-12 justify-center transition-colors ${active ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-700 hover:text-white'}`}
        title={label}
    >
        {icon}
    </button>
);

export default DrawToCode;

بناءً على طلبك لتحسين قسم "رسمة إلى كود" وتغيير تخطيطه ليكون **مرتباً من الأعلى إلى الأسفل** (شريط الأدوات بالأعلى، اللوحة في المنتصف، والخصائص بالأسفل)، سأقوم بإعادة بناء الملف بالكامل مع إضافة ميزات قوية مثل "التراجع/الإعادة" (Undo/Redo)، "تكرار العناصر"، وتحسينات على تجربة الرسم.

