            points: 100, 
            freeMarketingContentUsed: 0, 
            warnings: 0, 
            isBanned: false, 
            isNewUser: true, 
            referralCode, 
            referralCodeUsed: false 
        };
        users.push(newUser);
        safeSetItem('users', JSON.stringify(users));
        user = newUser;
    } else {
        // Update existing user profile picture if provided by social login
        if (socialUser.profilePictureUrl) {
            user.profilePictureUrl = socialUser.profilePictureUrl;
            // Update in the users list too
            users = users.map(u => u.email === user!.email ? { ...u, profilePictureUrl: socialUser.profilePictureUrl } : u);
            safeSetItem('users', JSON.stringify(users));
        }
    }

    const userToStore: User = { 
        name: user.name, 
        username: user.username || user.email.split('@')[0],
        email: user.email, 
        profilePictureUrl: user.profilePictureUrl, 
        plan: user.plan || 'free', 
        walletAddress: user.walletAddress, 
        points: user.points || 0, 
        freeMarketingContentUsed: user.freeMarketingContentUsed || 0,
        warnings: user.warnings || 0,
        isBanned: user.isBanned || false,
        isNewUser: user.isNewUser,
        referralCode: user.referralCode,
        referralCodeUsed: user.referralCodeUsed,
    };

    // Force a slight delay to ensure state propagates if rapid switching
    await new Promise(resolve => setTimeout(resolve, 100));

    safeSetItem('currentUser', JSON.stringify(userToStore));
    setCurrentUser(userToStore);
    return true;
  }

  const loginWithGoogle = async (): Promise<boolean> => {
