    const users: (User & { pass: string })[] = safeJsonParse(safeGetItem('users'), []);
    const reportedUserIndex = users.findIndex(u => u.email === reportedProject.ownerEmail);
    const reportingUserIndex = users.findIndex(u => u.email === currentUser.email);

    if (reportedUserIndex === -1) return { success: false, message: "Reported user not found." };
    if (reportingUserIndex === -1) return { success: false, message: "Could not identify reporting user."};

    // Simulate AI check. False report if reason includes "test_invalid"
    const isReportValid = !reason.toLowerCase().includes('test_invalid');

    if (isReportValid) {
        // Punish reported user
        const reportedUser = users[reportedUserIndex];
        reportedUser.points = Math.max(0, (reportedUser.points || 0) - 50);
        reportedUser.warnings = (reportedUser.warnings || 0) + 1;
        if (reportedUser.warnings >= 2) { reportedUser.isBanned = true; }
        users[reportedUserIndex] = reportedUser;

        safeSetItem('users', JSON.stringify(users));
        return { success: true, message: "تم إرسال البلاغ. تم تحذير المستخدم المبلغ عنه." };
    } else {
        // Punish reporter
        const reporter = users[reportingUserIndex];
        reporter.points = Math.max(0, (reporter.points || 0) - 50);
        reporter.warnings = (reporter.warnings || 0) + 1;
        if (reporter.warnings >= 2) { reporter.isBanned = true; }
        users[reportingUserIndex] = reporter;

        safeSetItem('users', JSON.stringify(users));
        // Update current user state if they are the one getting punished
        await updateUser({ points: reporter.points, warnings: reporter.warnings, isBanned: reporter.isBanned });

        return { success: true, message: "تم اعتبار بلاغك غير صالح. تم تسجيل تحذير لك." };
    }
  };

  const applyReferralCode = async (code: string): Promise<{ success: boolean; message: string }> => {
    if (!currentUser) return { success: false, message: 'يجب تسجيل الدخول أولاً.' };
    if (currentUser.referralCodeUsed) return { success: false, message: 'لقد استخدمت رمز إحالة بالفعل.' };
    if (currentUser.referralCode === code) return { success: false, message: 'لا يمكنك استخدام رمز الإحالة الخاص بك.' };

    const users: (User & { pass: string })[] = safeJsonParse(safeGetItem('users'), []);
    const referrerIndex = users.findIndex(u => u.referralCode === code);

    if (referrerIndex === -1) return { success: false, message: 'رمز الإحالة غير صالح.' };

    const referrer = users[referrerIndex];
    const referrerPoints = (referrer.points || 0) + 200; // Referrer gets 200 points
    users[referrerIndex] = { ...referrer, points: referrerPoints };

    const currentUserBonus = 50; // New user gets 50 points
    await updateUser({
        points: (currentUser.points || 0) + currentUserBonus,
        referralCodeUsed: true
    });

    safeSetItem('users', JSON.stringify(users));

    return { success: true, message: `تهانينا! لقد حصلت على ${currentUserBonus} نقطة. حصل صديقك على 200 نقطة.` };
  };


  return (
    <AuthContext.Provider value={{ currentUser, logout, updateUser, loginWithGoogle, loginWithFacebook, upgradePlan, redeemPointsForPlan, reportProject, applyReferralCode }}>
      {children}
    </AuthContext.Provider>
  );
};
```

